import Queue from "../../../../../../../../../../../subject_repositories/q/queue.js";

describe("Queue close behavior", () => {
  it("should resolve the closed promise after get is called on a closed queue", async () => {
    const queue = Queue();

    // Close the queue
    queue.close(new Error("test close error"));

    // Call get() to trigger the fail handler which should resolve the closed promise
    // The get() will reject since the queue is closed
    try {
      await queue.get();
    } catch (e) {
      // Expected to throw
    }

    // In the original code, the fail handler calls closed.resolve(error)
    // so queue.closed should now be resolved
    // In the mutated code, closed.resolve is never called, so queue.closed never resolves
    const closedResult = await Promise.race([
      queue.closed,
      new Promise((_, reject) => 
        setTimeout(() => reject(new Error("closed promise never resolved within timeout")), 500)
      )
    ]);

    expect(closedResult).toBeInstanceOf(Error);
  });
});
